import React, { useEffect, useRef, useState, useCallback } from 'react';
import { detectBlink, initializeFaceLandmarker } from '../services/visionService';
import { Fruit, FRUIT_TYPES, GameStats, FruitType } from '../types';

interface GameProps {
  onGameOver: (stats: GameStats) => void;
}

// Adjusted Thresholds
const BLINK_THRESHOLD = 0.5; // Increased to 0.5 to make it easier to register a blink
const DOUBLE_BLINK_TIME = 500; // ms window for double blink
const GAME_DURATION = 60; // seconds

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  // UI State
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(GAME_DURATION);
  const [isLoading, setIsLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [isMixing, setIsMixing] = useState(false);
  const [feedback, setFeedback] = useState<{text: string, id: number} | null>(null);
  const [pendingCount, setPendingCount] = useState(0); 
  const [isFaceDetected, setIsFaceDetected] = useState(false); // New: Track face status

  // Visual state for fruits sitting in the blender
  const [blenderFruits, setBlenderFruits] = useState<{id: string, type: FruitType, x: number, rot: number}[]>([]);

  // Refs for Game Logic
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);
  const fruitsRef = useRef<Fruit[]>([]);
  const lastSpawnRef = useRef<number>(0);
  const scoreRef = useRef(0);
  const collectedFruitsCountRef = useRef(0);

  // Logic Separation Refs
  const pendingFruitsRef = useRef<FruitType[]>([]); 
  const juiceLevelRef = useRef(0); 
  const mixColorRef = useRef<{r: number, g: number, b: number}>({r: 255, g: 255, b: 255});

  // Blink Detection Logic Refs
  const blinkStateRef = useRef<{
    lastBlinkTime: number;
    blinkCount: number;
    isEyesClosed: boolean;
  }>({ lastBlinkTime: 0, blinkCount: 0, isEyesClosed: false });

  // Helper to add fruit to blender when it arrives
  const addFruitToBlender = (fruitType: FruitType) => {
    pendingFruitsRef.current.push(fruitType);
    setPendingCount(pendingFruitsRef.current.length);

    setBlenderFruits(prev => [
      ...prev, 
      {
        id: Math.random().toString(36).substr(2, 9),
        type: fruitType,
        x: Math.random() * 60 + 20, 
        rot: Math.random() * 360    
      }
    ]);
  };

  // Helper to spawn a new fruit
  const spawnFruit = (canvasWidth: number) => {
    const type = FRUIT_TYPES[Math.floor(Math.random() * FRUIT_TYPES.length)];
    fruitsRef.current.push({
      id: Math.random().toString(),
      type,
      x: Math.random() * (canvasWidth - 60) + 30,
      y: -50,
      // Increased base speed from 2 to 3 for better flow
      speed: 3 + Math.random() * 2 + (collectedFruitsCountRef.current * 0.1),
      scale: 1,
      isCollected: false
    });
  };

  // Initialize Game & Camera
  useEffect(() => {
    let timerInterval: ReturnType<typeof setInterval> | undefined;
    let loadTimeout: ReturnType<typeof setTimeout> | undefined;

    const startCamera = async () => {
      try {
        // Set a timeout to warn user if AI takes too long
        loadTimeout = setTimeout(() => {
          if (isLoading) {
             setLoadError("Loading is taking longer than expected. Check your internet connection.");
          }
        }, 10000);

        console.log("Starting initialization...");
        await initializeFaceLandmarker();
        console.log("Camera requesting...");
        // Increased resolution for better eye tracking
        const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 640, height: 480 } });

        if (videoRef.current) {
          videoRef.current.srcObject = stream;

          const startLogic = () => {
            console.log("Video loaded. Starting game loop.");
            setIsLoading(false);
            if (loadTimeout) clearTimeout(loadTimeout);

            // Ensure video is playing
            videoRef.current?.play().catch(e => console.error("Play error:", e));

            startGameLoop();

            // Start Timer
            timerInterval = setInterval(() => {
              setTimeLeft((prev) => {
                if (prev <= 1) {
                  clearInterval(timerInterval);
                  cancelAnimationFrame(requestRef.current);
                  finishGame();
                  return 0;
                }
                return prev - 1;
              });
            }, 1000);
          };

          // Robust check for video readiness
          if (videoRef.current.readyState >= 2) {
             startLogic();
          } else {
             videoRef.current.onloadeddata = startLogic;
          }
        }
      } catch (err) {
        console.error("Camera error:", err);
        setLoadError("Failed to access camera. Please allow permissions and reload.");
        if (loadTimeout) clearTimeout(loadTimeout);
      }
    };

    startCamera();

    return () => {
      cancelAnimationFrame(requestRef.current);
      if (timerInterval) clearInterval(timerInterval);
      if (loadTimeout) clearTimeout(loadTimeout);

      if (videoRef.current && videoRef.current.srcObject) {
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const finishGame = () => {
    const r = Math.round(mixColorRef.current.r);
    const g = Math.round(mixColorRef.current.g);
    const b = Math.round(mixColorRef.current.b);
    onGameOver({
      score: scoreRef.current,
      fruitsCollected: collectedFruitsCountRef.current,
      juiceColor: `rgb(${r},${g},${b})`
    });
  };

  const showFeedback = (text: string) => {
    setFeedback({ text, id: Date.now() });
    setTimeout(() => setFeedback(null), 1000);
  };

  const handleSingleBlink = () => {
    // Collect closest fruit
    const activeFruits = fruitsRef.current.filter(f => !f.isCollected && f.y < window.innerHeight);
    if (activeFruits.length > 0) {
      // Find lowest fruit (closest to bottom)
      const target = activeFruits.reduce((prev, curr) => (prev.y > curr.y ? prev : curr));

      target.isCollected = true;
      scoreRef.current += target.type.score;
      collectedFruitsCountRef.current += 1;

      setScore(scoreRef.current);
      showFeedback(`Caught!`);
    } else {
      showFeedback(`Miss!`);
    }
  };

  const handleDoubleBlink = () => {
    if (isMixing) return;

    if (pendingFruitsRef.current.length === 0) {
        showFeedback("No fruits!");
        return;
    }

    setIsMixing(true);

    const count = pendingFruitsRef.current.length;
    const bonus = count * 20; 
    scoreRef.current += bonus;
    setScore(scoreRef.current);
    showFeedback(`MIXING! +${bonus}`);

    pendingFruitsRef.current.forEach(fruitType => {
        const hex = fruitType.color;
        const r = parseInt(hex.slice(1, 3), 16);
        const g = parseInt(hex.slice(3, 5), 16);
        const b = parseInt(hex.slice(5, 7), 16);

        if (juiceLevelRef.current === 0 && mixColorRef.current.r === 255) {
             mixColorRef.current = { r, g, b };
        } else {
             const weight = 0.15; 
             mixColorRef.current.r = mixColorRef.current.r * (1 - weight) + r * weight;
             mixColorRef.current.g = mixColorRef.current.g * (1 - weight) + g * weight;
             mixColorRef.current.b = mixColorRef.current.b * (1 - weight) + b * weight;
        }
    });

    juiceLevelRef.current = Math.min(juiceLevelRef.current + (count * 10), 100);

    pendingFruitsRef.current = [];
    setPendingCount(0);
    setBlenderFruits([]);

    setTimeout(() => {
      setIsMixing(false);
    }, 2000);
  };

  const processBlinkLogic = (leftOpen: number, rightOpen: number) => {
    // BOTH eyes must be closed below threshold
    const eyesClosed = leftOpen < BLINK_THRESHOLD && rightOpen < BLINK_THRESHOLD;
    const now = Date.now();

    if (eyesClosed && !blinkStateRef.current.isEyesClosed) {
        blinkStateRef.current.isEyesClosed = true;
    } else if (!eyesClosed && blinkStateRef.current.isEyesClosed) {
        // Eyes just opened -> Blink detected
        blinkStateRef.current.isEyesClosed = false;
        blinkStateRef.current.blinkCount++;
        blinkStateRef.current.lastBlinkTime = now;

        // Debounce logic
        setTimeout(() => {
            if (blinkStateRef.current.blinkCount === 1) {
               // Waiting for potential second blink...
            } else if (blinkStateRef.current.blinkCount >= 2) {
               handleDoubleBlink();
               blinkStateRef.current.blinkCount = 0; 
            }
        }, 50); // Small initial delay

        setTimeout(() => {
             if (blinkStateRef.current.blinkCount === 1) {
                 handleSingleBlink();
                 blinkStateRef.current.blinkCount = 0;
             }
        }, DOUBLE_BLINK_TIME);
    }
  };

  const startGameLoop = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const animate = (time: number) => {
      if (!canvasRef.current) return;

      // 1. Process Vision
      if (videoRef.current && !videoRef.current.paused && !videoRef.current.ended) {
        const result = detectBlink(videoRef.current);

        if (result.status === 'ok') {
          setIsFaceDetected(true);
          processBlinkLogic(result.leftOpen, result.rightOpen);
        } else if (result.status === 'no-face') {
          // Only explicitly set to false if the detector ran and found nothing
          setIsFaceDetected(false);
        }
        // If status is 'skipped' (frame didn't change), we preserve the previous state
        // This prevents flickering between True/False at high frame rates
      }

      // 2. Clear Canvas
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // 3. Spawn Fruits - Faster rate and multiple fruits
      // Base interval 900ms, gets faster. Every 5 fruits, spawn a burst.
      const spawnInterval = Math.max(900 - (collectedFruitsCountRef.current * 15), 400);

      if (time - lastSpawnRef.current > spawnInterval) { 
        spawnFruit(canvas.width);

        // Chance to spawn a second fruit simultaneously as difficulty increases
        if (collectedFruitsCountRef.current > 5 && Math.random() > 0.7) {
             setTimeout(() => spawnFruit(canvas.width), 200);
        }

        lastSpawnRef.current = time;
      }

      // 4. Update & Draw Fruits
      for (let i = fruitsRef.current.length - 1; i >= 0; i--) {
        const fruit = fruitsRef.current[i];

        if (fruit.isCollected) {
          // Fly to blender
          const targetX = canvas.width / 2;
          const targetY = canvas.height - 150; 

          const dx = targetX - fruit.x;
          const dy = targetY - fruit.y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < 30) {
              addFruitToBlender(fruit.type);
              fruitsRef.current.splice(i, 1);
              continue;
          }

          fruit.x += dx * 0.15;
          fruit.y += dy * 0.15;
          if (fruit.scale > 0.5) fruit.scale -= 0.05;

        } else {
          // Fall down
          fruit.y += fruit.speed;
          if (fruit.y > canvas.height) {
            fruitsRef.current.splice(i, 1);
            continue;
          }
        }

        // Draw
        ctx.font = `${40 * fruit.scale}px Arial`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(fruit.type.emoji, fruit.x, fruit.y);
      }

      requestRef.current = requestAnimationFrame(animate);
    };

    requestRef.current = requestAnimationFrame(animate);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="relative w-full h-screen bg-sky-50 overflow-hidden">
      {/* Loading Overlay */}
      {isLoading && (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-white">
          {loadError ? (
            <div className="text-center p-6">
              <div className="text-red-500 text-5xl mb-4">⚠️</div>
              <p className="text-xl font-bold text-red-600 mb-2">Error Loading Game</p>
              <p className="text-gray-600">{loadError}</p>
            </div>
          ) : (
            <>
              <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-orange-500 mb-4"></div>
              <p className="text-xl font-semibold text-gray-700">Loading AI Model...</p>
              <p className="text-sm text-gray-400 mt-2">Please allow camera access</p>
            </>
          )}
        </div>
      )}

      {/* Main Game Canvas */}
      <canvas ref={canvasRef} className="absolute inset-0 z-10" />

      {/* Camera Feed & Status */}
      <div className="absolute top-4 right-4 z-30 w-32 md:w-48 overflow-hidden rounded-xl border-4 border-white shadow-lg bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          muted 
          className="w-full h-full object-cover transform -scale-x-100" // Mirror flip
        />
        <div className={`absolute bottom-0 left-0 right-0 text-[10px] text-center py-1 font-bold ${isFaceDetected ? 'bg-green-500/80 text-white' : 'bg-red-500/80 text-white'}`}>
          {isFaceDetected ? "FACE DETECTED" : "NO FACE DETECTED"}
        </div>
      </div>

      {/* HUD: Score & Timer */}
      <div className="absolute top-4 left-4 z-30 flex gap-4">
        <div className="bg-white/90 backdrop-blur rounded-xl p-3 shadow-lg border-2 border-orange-100">
          <p className="text-xs text-gray-500 font-bold uppercase">Score</p>
          <p className="text-2xl font-bold text-orange-600">{score}</p>
        </div>
        <div className={`bg-white/90 backdrop-blur rounded-xl p-3 shadow-lg border-2 ${timeLeft < 10 ? 'border-red-500 animate-pulse' : 'border-blue-100'}`}>
          <p className="text-xs text-gray-500 font-bold uppercase">Time</p>
          <p className={`text-2xl font-bold ${timeLeft < 10 ? 'text-red-600' : 'text-blue-600'}`}>
            {timeLeft}s
          </p>
        </div>
      </div>

      {/* Feedback Popup */}
      {feedback && (
        <div key={feedback.id} className="absolute top-1/3 left-1/2 transform -translate-x-1/2 z-40 animate-bounce">
          <span className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-b from-yellow-400 to-red-500 drop-shadow-md stroke-white">
            {feedback.text}
          </span>
        </div>
      )}

      {/* Blender / Mixer Area */}
      <div className="absolute bottom-0 left-1/2 transform -translate-x-1/2 z-20 flex flex-col items-center">

        {/* Pending Fruit Indicator */}
        {pendingCount > 0 && !isMixing && (
           <div className="mb-2 bg-yellow-400 text-yellow-900 px-3 py-1 rounded-full text-xs font-bold animate-bounce border-2 border-yellow-200 shadow-md">
             Double Blink to Mix {pendingCount}!
           </div>
        )}

        {/* Mixer Body */}
        <div className={`relative w-40 h-48 bg-white/30 border-4 border-gray-400 rounded-b-3xl backdrop-blur-sm overflow-hidden flex items-end justify-center mb-8 ${isMixing ? 'shake' : ''}`}>

           {/* Fruits Inside Blender (Visual) */}
           {!isMixing && blenderFruits.map((f, i) => (
              <div 
                key={f.id}
                className="absolute text-2xl transition-all duration-300 ease-out"
                style={{
                  left: `${f.x}%`,
                  bottom: `${10 + (i * 4)}px`, // Stack them slightly
                  transform: `rotate(${f.rot}deg)`,
                  zIndex: 10
                }}
              >
                {f.type.emoji}
              </div>
           ))}

           {/* Liquid */}
           <div 
             className="w-full transition-all duration-1000 ease-in-out absolute bottom-0 left-0 right-0 z-0"
             style={{ 
               height: `${juiceLevelRef.current}%`, 
               backgroundColor: `rgb(${Math.round(mixColorRef.current.r)}, ${Math.round(mixColorRef.current.g)}, ${Math.round(mixColorRef.current.b)})`,
               opacity: 0.85
             }}
           >
             {isMixing && (
               <div className="w-full h-full opacity-50 bg-[url('https://www.transparenttextures.com/patterns/diagmonds-light.png')] animate-spin" style={{animationDuration: '0.5s'}}></div>
             )}
           </div>

           {/* Blade */}
           <div className={`absolute bottom-2 w-16 h-2 bg-gray-600 rounded-full z-20 ${isMixing ? 'animate-spin' : ''}`} style={{animationDuration: '0.1s'}}></div>
        </div>

        {/* Base */}
        <div className="w-48 h-12 bg-gray-800 rounded-t-xl -mt-8 shadow-2xl flex items-center justify-center border-t border-gray-600">
            <div className={`w-4 h-4 rounded-full ${isMixing ? 'bg-green-500 animate-pulse shadow-[0_0_10px_rgba(34,197,94,0.8)]' : 'bg-red-500'}`}></div>
        </div>
      </div>
    </div>
  );
};

export default Game;

import { FaceLandmarker, FilesetResolver } from "@mediapipe/tasks-vision";

let faceLandmarker: FaceLandmarker | null = null;
let initPromise: Promise<FaceLandmarker> | null = null;
let lastVideoTime = -1;

export type BlinkResult = 
  | { status: 'ok'; leftOpen: number; rightOpen: number }
  | { status: 'no-face' }
  | { status: 'skipped' } // Video frame hasn't changed
  | { status: 'loading' }; // Model not ready

export async function initializeFaceLandmarker() {
  if (faceLandmarker) return faceLandmarker;
  if (initPromise) return initPromise;

  console.log("Initializing FaceLandmarker...");

  initPromise = (async () => {
    try {
      // Patch console methods to suppress specific TFLite messages
      const originalInfo = console.info;
      const originalLog = console.log;
      const originalWarn = console.warn;

      const shouldFilter = (args: any[]) => {
        // Convert all arguments to a string to catch the message wherever it appears
        const msg = args.map(a => String(a)).join(' ');
        return msg.includes('Created TensorFlow Lite XNNPACK delegate for CPU');
      };

      console.info = (...args) => {
        if (!shouldFilter(args)) originalInfo.apply(console, args);
      };

      console.log = (...args) => {
        if (!shouldFilter(args)) originalLog.apply(console, args);
      };

      console.warn = (...args) => {
        if (!shouldFilter(args)) originalWarn.apply(console, args);
      };

      // Use a newer, stable WASM version matching package.json
      const filesetResolver = await FilesetResolver.forVisionTasks(
        "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.18/wasm"
      );

      faceLandmarker = await FaceLandmarker.createFromOptions(filesetResolver, {
        baseOptions: {
          modelAssetPath: `https://storage.googleapis.com/mediapipe-models/face_landmarker/face_landmarker/float16/1/face_landmarker.task`,
          delegate: "GPU" // Prefer GPU for performance
        },
        outputFaceBlendshapes: true,
        runningMode: "VIDEO",
        numFaces: 1,
      });

      // Restore console methods
      console.info = originalInfo;
      console.log = originalLog;
      console.warn = originalWarn;

      console.log("FaceLandmarker initialized successfully!");
      return faceLandmarker;
    } catch (e) {
      console.error("Failed to initialize FaceLandmarker:", e);
      throw e;
    }
  })();

  return initPromise;
}

export function detectBlink(video: HTMLVideoElement): BlinkResult {
  // Safety checks
  if (!faceLandmarker) return { status: 'loading' };
  if (!video || !video.videoWidth || !video.videoHeight) return { status: 'skipped' };
  if (video.paused || video.ended) return { status: 'skipped' };

  try {
    const nowInMs = Date.now();

    // Only process if video time has advanced
    if (lastVideoTime !== video.currentTime) {
      lastVideoTime = video.currentTime;

      const results = faceLandmarker.detectForVideo(video, nowInMs);

      if (results.faceBlendshapes && results.faceBlendshapes.length > 0 && results.faceBlendshapes[0].categories) {
        const categories = results.faceBlendshapes[0].categories;

        // Extract blink scores (0 = open, 1 = closed)
        const leftBlink = categories.find(c => c.categoryName === 'eyeBlinkLeft')?.score || 0;
        const rightBlink = categories.find(c => c.categoryName === 'eyeBlinkRight')?.score || 0;

        return {
          status: 'ok',
          leftOpen: 1 - leftBlink,
          rightOpen: 1 - rightBlink
        };
      } else {
        return { status: 'no-face' };
      }
    }

    return { status: 'skipped' };
  } catch (error) {
    console.error("Error during detection:", error);
    return { status: 'no-face' };
  }
}
